// Extract job cards from rendered HTML
// GTMfund filtered by ?jobTypes=Customer+Success+Manager

const html = $input.first().json.data || $input.first().json;

if (typeof html !== 'string') {
  console.log('Response is not HTML string:', typeof html);
  return [{ json: { _noJobs: true, message: 'Invalid response type' } }];
}

console.log('HTML length:', html.length);

// Extract job cards - look for links with /jobs/ pattern
const jobLinkPattern = /<a[^>]*href=\"(\/jobs\/[^\"]+)\"[^>]*>([\s\S]*?)<\/a>/gi;
const jobs = [];
let match;

while ((match = jobLinkPattern.exec(html)) !== null) {
  const href = match[1];
  const content = match[2];

  // Skip navigation links
  if (href === '/jobs' || href === '/jobs/') continue;

  // Clean up the content - remove HTML tags
  const text = content.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  const lines = text.split(/\s{2,}/).filter(l => l.trim());

  if (lines.length >= 1 && lines[0].length > 3) {
    jobs.push({
      title: lines[0] || '',
      company: lines[1] || '',
      location: lines[2] || '',
      url: 'https://jobs.gtmfund.com' + href
    });
  }
}

console.log('Extracted', jobs.length, 'job cards from HTML');

if (jobs.length === 0) {
  // Check if page has job content at all
  const hasJobContent = html.includes('Customer Success') || html.includes('job-card');
  return [{ json: { _noJobs: true, message: hasJobContent ? 'Jobs found but extraction failed' : 'No jobs in HTML', htmlSample: html.slice(0, 1000) } }];
}

return [{ json: { jobs, count: jobs.length } }];

// Parse GTMfund jobs from HTML extraction
// URL filter applied: ?jobTypes=Customer+Success+Manager

const input = $input.first().json;

if (input._noJobs) {
  return [{ json: input }];
}

const jobs = input.jobs || [];

function normalizeText(text) {
  return (text || '').toLowerCase().trim();
}

console.log(`Processing ${jobs.length} jobs from extraction`);

const parsedJobs = [];
const seen = new Set();

for (const job of jobs) {
  const title = job.title || '';
  const company = job.company || 'Unknown';
  const url = job.url || '';

  // Skip if no title or duplicate URL
  if (!title || seen.has(url)) continue;
  seen.add(url);

  parsedJobs.push({
    title: title,
    company: company,
    location: job.location || 'Remote',
    salary: '',
    url: url,
    source: 'GTMfund',
    description: '',
    job_id: `gtmfund:${normalizeText(company)}:${normalizeText(title)}`.replace(/[^a-z0-9:]/g, '-')
  });
}

console.log(`Found ${parsedJobs.length} unique jobs from GTMfund`);

if (parsedJobs.length === 0) {
  return [{ json: { _noJobs: true, message: 'No jobs found after dedup' } }];
}

return parsedJobs.map(job => ({ json: job }));

// Dedup against existing Airtable records

const newJobs = $('Parse & Filter CX Roles').all();
const existingJobs = $('Search Existing Jobs').all();

// Build lookup set from existing jobs
const existingKeys = new Set();
for (const existing of existingJobs) {
  const company = (existing.json.Company || '').toLowerCase().trim();
  const title = (existing.json['Job Title'] || '').toLowerCase().trim();
  const url = (existing.json['Job URL'] || '').toLowerCase().trim();

  // Key by URL (most reliable)
  if (url) existingKeys.add(url);

  // Also key by company+title combo
  if (company && title) {
    existingKeys.add(`${company}:${title}`);
  }
}

console.log(`Existing GTMfund jobs in Airtable: ${existingKeys.size}`);

// Filter out duplicates
const uniqueJobs = [];
for (const job of newJobs) {
  if (job.json._noJobs) continue;

  const url = (job.json.url || '').toLowerCase().trim();
  const company = (job.json.company || '').toLowerCase().trim();
  const title = (job.json.title || '').toLowerCase().trim();
  const companyTitleKey = `${company}:${title}`;

  if (existingKeys.has(url) || existingKeys.has(companyTitleKey)) {
    console.log(`Skipping duplicate: ${job.json.company} - ${job.json.title}`);
    continue;
  }

  uniqueJobs.push(job);
}

console.log(`New GTMfund jobs to evaluate: ${uniqueJobs.length}`);

if (uniqueJobs.length === 0) {
  return [{ json: { _noJobs: true, message: 'All jobs already in Airtable' } }];
}

return uniqueJobs;

// Map fields for Job Evaluation Pipeline v6.1

const jobs = $input.all();
const mappedJobs = [];

for (const job of jobs) {
  if (job.json._noJobs) continue;

  mappedJobs.push({
    json: {
      'Job Title': job.json.title,
      'Company': job.json.company,
      'Location': job.json.location,
      'Salary Info': job.json.salary,
      'Job URL': job.json.url,
      'Source': 'GTMfund',
      'Job ID': job.json.job_id,
      'Date Found': new Date().toISOString().split('T')[0],
      '_description': job.json.description
    }
  });
}

console.log(`Mapped ${mappedJobs.length} GTMfund jobs for evaluation`);

return mappedJobs;
